#### **2. ⚠️ HIGH: No Input Validation**
**Issue:** Query parameters and headers are not validated or sanitized.
- Vulnerable to query parameter pollution attacks
- Could enable parameter tampering

**Recommendation:** Implement input validation
```javascript
const { query, validationResult } = require('express-validator');

app.get('/users', 
  query('limit').optional().isInt({ min: 1, max: 100 }),
  query('offset').optional().isInt({ min: 0 }),
  (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }
    res.json([...]);
  }
);
```

---

#### **3. ⚠️ HIGH: No HTTPS/TLS Enforcement**
**Issue:** Server runs on plain HTTP without TLS encryption.
- Sensitive data (user emails) transmitted in plaintext
- Vulnerable to man-in-the-middle (MITM) attacks

**Recommendation:** Implement HTTPS
```javascript
const https = require('https');
const fs = require('fs');

const options = {
  key: fs.readFileSync('path/to/private-key.pem'),
  cert: fs.readFileSync('path/to/certificate.pem')
};

https.createServer(options, app).listen(3000, () => {
  console.log('Server running on HTTPS port 3000');
});
```

---

#### **4. ⚠️ HIGH: Missing Security Headers**
**Issue:** No security headers are configured (CORS, CSP, X-Frame-Options, etc.)
- Vulnerable to XSS, clickjacking, and CORS attacks
- Information disclosure risks

**Recommendation:** Add security headers middleware
```javascript
const helmet = require('helmet');
const cors = require('cors');

app.use(helmet()); // Adds multiple security headers

// Configure CORS properly (don't use wildcard in production)
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || ['http://localhost:3000'],
  credentials: true,
  methods: ['GET', 'POST'],
  allowedHeaders: ['Content-Type', 'Authorization']
}));

// Additional headers
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  next();
});
```

